frappe.ui.form.on('Report Card Generator', {
	refresh: function(frm) {
		frm.page.set_primary_action(__('Generate Report Cards'), function() {
			generate_report_cards(frm);
		});
		frm.add_custom_button(__('Preview'), function() {
			frappe.msgprint('Preview will open the first Report Card for the selected academic year.');
		});
	},
	generation_mode: function(frm) {
		frm.refresh_fields();
	}
});

function generate_report_cards(frm) {
	if (!frm.doc.academic_year) {
		frappe.msgprint(__('Please select an Academic Year'));
		return;
	}

	if (frm.doc.generation_mode === 'Single Student' && !frm.doc.student) {
		frappe.msgprint(__('Please select a Student'));
		return;
	}

	if (frm.doc.generation_mode === 'Student Group' && !frm.doc.student_group) {
		frappe.msgprint(__('Please select a Student Group'));
		return;
	}

	let msg = `Generate Report Cards for ${frm.doc.academic_year}`;
	if (frm.doc.generation_mode === 'Single Student' && frm.doc.student) msg += ` — ${frm.doc.student}`;
	else if (frm.doc.generation_mode === 'Student Group' && frm.doc.student_group) msg += ` — ${frm.doc.student_group}`;
	else msg += ' (All Students)';

	frappe.confirm(msg + '?', function() {
		frappe.show_alert({ message: __('Generating...'), indicator: 'blue' });
		frappe.call({
			method: 'education.education.doctype.report_card_generator.report_card_generator.generate_report_cards',
			args: {
				generation_mode: frm.doc.generation_mode,
				academic_year: frm.doc.academic_year,
				student: frm.doc.student,
				student_group: frm.doc.student_group
			},
			callback: function(r) {
				if (r.message && r.message.status === 'success') {
					frappe.show_alert({ message: r.message.message, indicator: 'green' });
					frappe.msgprint(r.message.message);
				} else {
					frappe.show_alert({ message: r.message.message || 'Error', indicator: 'red' });
					frappe.msgprint(r.message.message || 'Generation failed.');
				}
			}
		});
	});
}
